import{_ as o,o as t,c as a,a4 as r}from"./chunks/framework.LQ2Ga-wM.js";const p=JSON.parse('{"title":"Météo & Temps","description":"","frontmatter":{},"headers":[],"relativePath":"framework/modules/weather.md","filePath":"framework/modules/weather.md","lastUpdated":1781601194000}'),s={name:"framework/modules/weather.md"};function c(d,e,n,i,l,m){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="meteo-temps" tabindex="-1">Météo &amp; Temps <a class="header-anchor" href="#meteo-temps" aria-label="Permalink to &quot;Météo &amp; Temps&quot;">​</a></h1><div class="danger custom-block"><p class="custom-block-title">Retiré du core</p><p>La gestion de la météo et du temps <strong>ne fait plus partie de <code>lo</code></strong>. Le module météo de l&#39;ancienne architecture (cycle jour/nuit, séquences, zones météo, blackout, commandes <code>/weather</code> et <code>/time</code>) a été supprimé du framework.</p></div><h2 id="ce-qui-a-change" tabindex="-1">Ce qui a changé <a class="header-anchor" href="#ce-qui-a-change" aria-label="Permalink to &quot;Ce qui a changé&quot;">​</a></h2><p><code>lo</code> (version 2.0.0) ne déclare plus <code>provide &#39;weathersync&#39;</code> dans son <code>fxmanifest.lua</code> : il ne fournit que <code>rsg-core</code> et <code>rsg-inventory</code>. Il n&#39;expose donc :</p><ul><li>ni table <code>Core.Weather</code> / <code>Core.WeatherData</code>,</li><li>ni exports <code>weathersync:*</code> (<code>setWeather</code>, <code>getTime</code>, <code>setBlackout</code>...),</li><li>ni commandes staff météo, menu, séquences ou zones,</li><li>ni champs météo dans <code>Config</code>.</li></ul><h2 id="comment-gerer-la-meteo-desormais" tabindex="-1">Comment gérer la météo désormais <a class="header-anchor" href="#comment-gerer-la-meteo-desormais" aria-label="Permalink to &quot;Comment gérer la météo désormais&quot;">​</a></h2><p>La météo et le temps sont délégués à une <strong>ressource externe dédiée</strong>, démarrée à part dans le <code>server.cfg</code>. Comme <code>lo</code> ne fournit plus <code>weathersync</code>, vous êtes libre d&#39;utiliser la ressource météo de votre choix, sans risque de double détection.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Le reste du HUD (santé, endurance, faim, soif...) reste géré par <code>lo</code> : voir <a href="./hud">Module HUD</a>. Seule la météo/temps a été externalisée.</p></div>',8)])])}const h=o(s,[["render",c]]);export{p as __pageData,h as default};
